k.api.post('login', (body: { userName: string, password: string }) => {
  const { userName, password } = body
  return { success: true }
})

// 字段较多：定义接口
interface CreateOrderBody {
  productId: string
  quantity: number
  remark?: string
}
k.api.post('create-order', (body: CreateOrderBody) => {
  const { productId, quantity, remark } = body
  const order = k.DB.sqlite.orders.add({ productId, quantity, remark })
  return { success: true, orderId: order._id }
})

