import { ksql, DataTypes } from 'module/k_sqlite'

// 定义模型
const User = ksql.define('users', {
    userName: { type: DataTypes.String, required: true },
    email: { type: DataTypes.String, unique: true, index: true },
    password: { type: DataTypes.String, required: true },
    age: { type: DataTypes.Number },
    isActive: { type: DataTypes.Boolean, default: true }
}, { timestamps: true })

// 注意: k_sqlite 是同步操作，不需要 await

// 创建
